func newGroupService_ListGroupUsersCmd(getCfg func() *config.Config, getOutput func() string) *cobra.Command {
	var flag_ListGroupUsers_SortingColumn string

	cmd := &cobra.Command{
		Use:     "list-users",
		Short:   "List group users",
		Long:    "List Group Users",
		Example: "  groups list-users --sorting-column GROUP_USER_FIELD_NAME_UNSPECIFIED",
		RunE: func(cmd *cobra.Command, args []string) error {
			req := &grouppb.ListGroupUsersRequest{}

			// Check for JSON input via --from-json or --request-json flags
			useJSON, _ := cmd.Flags().GetBool("from-json")
			requestJSON, _ := cmd.Flags().GetString("request-json")
			if requestJSON != "" {
				useJSON = true
			}
			if useJSON {
				var data []byte
				if requestJSON != "" {
					data = []byte(requestJSON)
				} else {
					var err error
					data, err = io.ReadAll(os.Stdin)
					if err != nil {
						return fmt.Errorf("reading stdin: %w", err)
					}
				}
				if err := protojson.Unmarshal(data, req); err != nil {
					return fmt.Errorf("parsing JSON input: %w", err)
				}
			}

			if !useJSON {
				if flag_ListGroupUsers_SortingColumn != "" {
					enumVal, ok := grouppb.GroupUserFieldName_value[flag_ListGroupUsers_SortingColumn]
					if !ok {
						return fmt.Errorf("invalid value %q for --sorting-column", flag_ListGroupUsers_SortingColumn)
					}
					ev := grouppb.GroupUserFieldName(enumVal)
					req.SortingColumn = &ev
				}
			}

			// Dry-run: print request and exit without calling the API
			dryRun, _ := cmd.Flags().GetBool("dry-run")
			if dryRun {
				reqJSON, err := protojson.MarshalOptions{Indent: "  "}.Marshal(req)
				if err != nil {
					return fmt.Errorf("marshalling request: %w", err)
				}
				envelope := map[string]json.RawMessage{
					"method":  json.RawMessage(fmt.Sprintf("%q", "zitadel.group.v2.GroupService/ListGroupUsers")),
					"request": json.RawMessage(reqJSON),
				}
				out, _ := json.MarshalIndent(envelope, "", "  ")
				fmt.Println(string(out))
				return nil
			}

			cfg := getCfg()
			actx, _, err := config.ActiveCtx(cfg)
			if err != nil {
				return err
			}
			tokenSource, err := auth.TokenSource(cmd.Context(), actx)
			if err != nil {
				return err
			}
			httpClient := client.New(tokenSource)
			baseURL := client.InstanceURL(actx.Instance)
			svcClient := groupconnect.NewGroupServiceClient(httpClient, baseURL)

			resp, err := svcClient.ListGroupUsers(cmd.Context(), connect.NewRequest(req))
			if err != nil {
				return FormatConnectError(err)
			}

			if getOutput() == "json" {
				return output.JSON(resp.Msg)
			}

			header := []string{"ORGANIZATION ID", "GROUP ID", "CREATION DATE"}
			var rows [][]string
			for _, item := range resp.Msg.GetGroupUsers() {
				rows = append(rows, []string{
					fmt.Sprint(item.GetOrganizationId()),
					fmt.Sprint(item.GetGroupId()),
					func() string {
						if t := item.GetCreationDate(); t != nil {
							return t.AsTime().Format("2006-01-02T15:04:05Z")
						}
						return ""
					}(),
				})
			}
			output.Table(header, rows)
			return nil
		},
	}

	cmd.Flags().StringVar(&flag_ListGroupUsers_SortingColumn, "sorting-column", "", "SortingColumn defines the field the result is sorted by. (one of: USER_ID, GROUP_ID, CREATION_DATE)")
	_ = cmd.RegisterFlagCompletionFunc("sorting-column", func(_ *cobra.Command, _ []string, _ string) ([]string, cobra.ShellCompDirective) {
		return []string{"GROUP_USER_FIELD_NAME_UNSPECIFIED", "GROUP_USER_FIELD_NAME_USER_ID", "GROUP_USER_FIELD_NAME_GROUP_ID", "GROUP_USER_FIELD_NAME_CREATION_DATE"}, cobra.ShellCompDirectiveNoFileComp
	})

	return cmd
}
